package shell

import (
	"bufio"
	"bytes"
	"context"
	"errors"
	"fmt"
	"io"
	"strings"

	"github.com/SeungKang/memshonk/internal/apicompat"

	"mvdan.cc/sh/v3/expand"
	"mvdan.cc/sh/v3/interp"
	"mvdan.cc/sh/v3/syntax"
)

var (
	// errHandledBuiltin is returned when a builtin is
	// handled by this library. Since the sh library
	// does not provide a way to cancel its own builtin
	// code, we need to return a non-nil error to
	// force sh to skip its own logic. We also need
	// a way to check if said error was generated by
	// our custom code, which is what this error
	// object does.
	errHandledBuiltin = errors.New("builtin handled by custom handler")
)

// NewInterpreter creates a new shell interpreter.
func NewInterpreter(session apicompat.Session, cmdHandler *apicompat.CommandHandler) (*Interpreter, error) {
	i := &Interpreter{
		session: session,
		cmdHand: cmdHandler,
		parser:  syntax.NewParser(),
	}

	sio := session.IO()

	// Use an empty reader for stdin to avoid competing
	// with readline for input. Built-in commands don't
	// read from stdin, and external commands that need
	// stdin piping would require a different approach
	// (e.g., temporarily giving them exclusive access
	// to the terminal).
	emptyStdin := bytes.NewReader(nil)

	runner, err := interp.New(
		interp.StdIO(emptyStdin, sio.Stdout, sio.Stderr),
		interp.Env(expand.ListEnviron(session.SharedState().Vars.KeyValues(nil)...)),
		interp.CallHandler(i.builtinHandler),
		interp.ExecHandlers(i.execHandler),
	)
	if err != nil {
		return nil, fmt.Errorf("failed to create interpreter - %w", err)
	}

	i.runner = runner

	return i, nil
}

// Interpreter wraps mvdan/sh to provide shell interpretation with built-in
// command routing.
type Interpreter struct {
	session apicompat.Session
	cmdHand *apicompat.CommandHandler
	parser  *syntax.Parser
	runner  *interp.Runner
}

// builtinHandler overrides some broken builtins in the sh library.
func (o *Interpreter) builtinHandler(ctx context.Context, argv []string) ([]string, error) {
	switch argv[0] {
	case "help", "jobs":
		// Unfortunately, the sh library added "help" and "jobs"
		// as builtins that always fail with an error stating:
		// "unimplemented builtin". So we need to override them
		// here.
		err := o.internalExec(ctx, argv)
		if err != nil {
			return argv, err
		}

		return argv, errHandledBuiltin
	default:
		return argv, nil
	}
}

// ExecuteScript parses and executes a shell script.
func (o *Interpreter) ExecuteScript(ctx context.Context, src io.Reader, name string) error {
	r := bufio.NewReader(src)

	header, err := r.ReadBytes('\n')
	if err != nil {
		return fmt.Errorf("failed to read script header (first line of script) - %w", err)
	}

	header = bytes.TrimRight(header, "\r\n")

	if !bytes.HasPrefix(header, []byte{'#', '!'}) {
		return fmt.Errorf("script header line should start with '#!', found: %q",
			header)
	}

	if !bytes.HasSuffix(header, []byte("/memshonk")) {
		return fmt.Errorf("first line of script must be '#!/<path>/memshonk', got %q",
			header)
	}

	err = o.Execute(ctx, r, name)
	if err != nil {
		return fmt.Errorf("script error - %w", err)
	}

	return nil
}

// Execute parses and executes a shell command line.
func (o *Interpreter) Execute(ctx context.Context, src io.Reader, optName string) error {
	file, err := o.parser.Parse(src, optName)
	if err != nil {
		return fmt.Errorf("parse error - %w", err)
	}

	return o.runner.Run(ctx, file)
}

// execHandler routes command execution to built-in commands
// or external programs.
func (o *Interpreter) execHandler(interp.ExecHandlerFunc) interp.ExecHandlerFunc {
	return func(ctx context.Context, argv []string) error {
		return o.internalExec(ctx, argv)
	}
}

func (o *Interpreter) internalExec(ctx context.Context, argv []string) error {
	// interp.HandlerCtx is the prescribed mechanism
	// for accesing the stdin/out pipes managed by
	// the sh library.
	handlerCtx := interp.HandlerCtx(ctx)

	err := o.cmdHand.Run(ctx, apicompat.RunCommandConfig{
		Argv:   argv,
		Env:    execEnv(handlerCtx.Env),
		Cwd:    handlerCtx.Dir,
		Stdin:  handlerCtx.Stdin,
		Stdout: handlerCtx.Stdout,
		Stderr: handlerCtx.Stderr,
	})
	if err != nil {
		exitStatus, hasIt := err.HasExitStatus()
		if !hasIt {
			exitStatus = 1
		}

		return interp.NewExitStatus(exitStatus)
	}

	return nil
}

// execEnv is a copy of the private function of the same name from
// mvdan.cc/sh/v3, interp/vars.go
func execEnv(env expand.Environ) []string {
	list := make([]string, 0, 64)
	env.Each(func(name string, vr expand.Variable) bool {
		if !vr.IsSet() {
			// If a variable is set globally but unset in the
			// runner, we need to ensure it's not part of the final
			// list. Seems like zeroing the element is enough.
			// This is a linear search, but this scenario should be
			// rare, and the number of variables shouldn't be large.
			for i, kv := range list {
				if strings.HasPrefix(kv, name+"=") {
					list[i] = ""
				}
			}
		}
		if vr.Exported && vr.Kind == expand.String {
			list = append(list, name+"="+vr.String())
		}
		return true
	})
	return list
}
